import{_ as t,c as e,o as i,a1 as l}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"高度な機能: マルチエージェントとスキル開発 | OpenSkills","description":"OpenSkillsの高度な機能を学びます。マルチエージェント環境の設定、カスタムスキルの開発、CI/CD統合、セキュリティ機能を通じて、複雑なシナリオを効率的に管理します。","frontmatter":{"title":"高度な機能: マルチエージェントとスキル開発 | OpenSkills","sidebarTitle":"マルチアカウントとカスタムスキル","subtitle":"高度な機能: マルチエージェントとスキル開発","description":"OpenSkillsの高度な機能を学びます。マルチエージェント環境の設定、カスタムスキルの開発、CI/CD統合、セキュリティ機能を通じて、複雑なシナリオを効率的に管理します。","order":3},"headers":[],"relativePath":"ja/numman-ali/openskills/advanced/index.md","filePath":"ja/numman-ali/openskills/advanced/index.md"}'),s={name:"ja/numman-ali/openskills/advanced/index.md"};function r(d,a,n,h,o,p){return i(),e("div",null,[...a[0]||(a[0]=[l('<h1 id="高度な機能" tabindex="-1">高度な機能 <a class="header-anchor" href="#高度な機能" aria-label="Permalink to &quot;高度な機能&quot;">​</a></h1><p>本節では、OpenSkillsの高度な使用方法について説明します。マルチエージェント環境の設定、カスタム出力、シンボリックリンク開発、スキル作成、CI/CD統合、およびセキュリティメカニズムが含まれます。これらの内容を習得すると、複雑なシナリオでスキルを効率的に管理し、独自のスキルライブラリを作成できるようになります。</p><div class="warning custom-block"><p class="custom-block-title">前提条件</p><p>本節を学習する前に、以下を完了していることを確認してください：</p><ul><li><a href="./../start/quick-start/">クイックスタート</a>：基本的なインストールと使用フローを理解する</li><li><a href="./../start/first-skill/">最初のスキルをインストール</a>：スキルのインストール方法を習得する</li><li><a href="./../start/sync-to-agents/">AGENTS.mdへのスキル同期</a>：スキル同期メカニズムを理解する</li></ul></div><h2 id="本章の内容" tabindex="-1">本章の内容 <a class="header-anchor" href="#本章の内容" aria-label="Permalink to &quot;本章の内容&quot;">​</a></h2><h3 id="マルチエージェントと出力設定" tabindex="-1">マルチエージェントと出力設定 <a class="header-anchor" href="#マルチエージェントと出力設定" aria-label="Permalink to &quot;マルチエージェントと出力設定&quot;">​</a></h3><table tabindex="0"><thead><tr><th>チュートリアル</th><th>説明</th></tr></thead><tbody><tr><td>---</td><td>---</td></tr></tbody></table><h3 id="スキル開発" tabindex="-1">スキル開発 <a class="header-anchor" href="#スキル開発" aria-label="Permalink to &quot;スキル開発&quot;">​</a></h3><table tabindex="0"><thead><tr><th>チュートリアル</th><th>説明</th></tr></thead><tbody><tr><td><a href="./symlink-support/">シンボリックリンクサポート</a></td><td>シンボリックリンクを使用してgitベースのスキル更新とローカル開発ワークフローを実現し、複数プロジェクトでスキルを共有する</td></tr><tr><td><a href="./create-skills/">カスタムスキルの作成</a></td><td>ゼロからSKILL.mdスキルファイルを作成し、YAMLフロントマターとディレクトリ構造の規範を習得する</td></tr><tr><td><a href="./skill-structure/">スキル構造の詳細</a></td><td>SKILL.mdの完全なフィールド仕様、references/scripts/assetsリソース設計、パフォーマンス最適化を深く理解する</td></tr></tbody></table><h3 id="自動化とセキュリティ" tabindex="-1">自動化とセキュリティ <a class="header-anchor" href="#自動化とセキュリティ" aria-label="Permalink to &quot;自動化とセキュリティ&quot;">​</a></h3><table tabindex="0"><thead><tr><th>チュートリアル</th><th>説明</th></tr></thead><tbody><tr><td><a href="./security/">セキュリティの説明</a></td><td>パストラバーサル保護、シンボリックリンクの安全な処理、YAML解析のセキュリティなど、3層の保護メカニズムについて理解する</td></tr></tbody></table><h3 id="総合ガイド" tabindex="-1">総合ガイド <a class="header-anchor" href="#総合ガイド" aria-label="Permalink to &quot;総合ガイド&quot;">​</a></h3><table tabindex="0"><thead><tr><th>チュートリアル</th><th>説明</th></tr></thead><tbody><tr><td><a href="./best-practices/">ベストプラクティス</a></td><td>プロジェクト設定、スキル管理、チームコラボレーションの経験のまとめ。OpenSkillsを効率的に使用するのに役立ちます</td></tr></tbody></table><h2 id="学習パスの推奨" tabindex="-1">学習パスの推奨 <a class="header-anchor" href="#学習パスの推奨" aria-label="Permalink to &quot;学習パスの推奨&quot;">​</a></h2><p>使用シナリオに応じて、適切な学習パスを選択してください：</p><h3 id="パスa-マルチエージェントユーザー" tabindex="-1">パスA：マルチエージェントユーザー <a class="header-anchor" href="#パスa-マルチエージェントユーザー" aria-label="Permalink to &quot;パスA：マルチエージェントユーザー&quot;">​</a></h3><p>複数のAIコーディングツール（Claude Code + Cursor + Windsurfなど）を同時に使用する場合：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Universalモード → カスタム出力パス → ベストプラクティス</span></span></code></pre></div><h3 id="パスb-スキル作成者" tabindex="-1">パスB：スキル作成者 <a class="header-anchor" href="#パスb-スキル作成者" aria-label="Permalink to &quot;パスB：スキル作成者&quot;">​</a></h3><p>独自のスキルを作成してチームと共有したい場合：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>カスタムスキルの作成 → スキル構造の詳細 → シンボリックリンクサポート → ベストプラクティス</span></span></code></pre></div><h3 id="パスc-devops-自動化" tabindex="-1">パスC：DevOps/自動化 <a class="header-anchor" href="#パスc-devops-自動化" aria-label="Permalink to &quot;パスC：DevOps/自動化&quot;">​</a></h3><p>CI/CDプロセスでOpenSkillsを統合する必要がある場合：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CI/CD統合 → セキュリティの説明 → ベストプラクティス</span></span></code></pre></div><h3 id="パスd-完全な学習" tabindex="-1">パスD：完全な学習 <a class="header-anchor" href="#パスd-完全な学習" aria-label="Permalink to &quot;パスD：完全な学習&quot;">​</a></h3><p>すべての高度な機能を包括的に習得したい場合、以下の順序で学習してください：</p><ol><li><a href="./universal-mode/">Universalモード</a> - マルチエージェント環境の基礎</li><li><a href="./custom-output-path/">カスタム出力パス</a> - 柔軟な出力設定</li><li><a href="./symlink-support/">シンボリックリンクサポート</a> - 効率的な開発ワークフロー</li><li><a href="./create-skills/">カスタムスキルの作成</a> - スキル作成の入門</li><li><a href="./skill-structure/">スキル構造の詳細</a> - スキル形式の深い理解</li><li><a href="./ci-integration/">CI/CD統合</a> - 自動化デプロイ</li><li><a href="./security/">セキュリティの説明</a> - セキュリティメカニズムの詳細</li><li><a href="./best-practices/">ベストプラクティス</a> - 経験のまとめ</li></ol><h2 id="次のステップ" tabindex="-1">次のステップ <a class="header-anchor" href="#次のステップ" aria-label="Permalink to &quot;次のステップ&quot;">​</a></h2><p>本節を完了した後、以下ができます：</p><ul><li><a href="./../faq/faq/">よくある質問</a>を参照して、使用中に発生する問題を解決する</li><li><a href="./../appendix/cli-api/">CLI APIリファレンス</a>を参照して、完全なコマンドラインインターフェースを理解する</li><li><a href="./../appendix/agents-md-format/">AGENTS.mdフォーマット仕様</a>を読んで、生成されるファイル形式を深く理解する</li><li><a href="./../changelog/changelog/">更新履歴</a>を確認して、最新の機能と変更を理解する</li></ul>',29)])])}const b=t(s,[["render",r]]);export{u as __pageData,b as default};
